    function updateCities() {
        var wilayaSelect = document.querySelector("select[name='" + nameWilaya + "']");
        var communeSelect = document.querySelector("select[name='" + nameCommune + "']");
        var selectedWilaya = wilayaSelect.value;

        communeSelect.innerHTML = '<option value="" selected disabled>اختر البلدية</option>';

        if (communes[selectedWilaya]) {
            communes[selectedWilaya].forEach(commune => {
                var option = document.createElement("option");
                option.value = commune;
                option.innerHTML = commune;
                communeSelect.appendChild(option);
            });
        }
    }

    document.addEventListener("DOMContentLoaded", updateWilayas);
